Script.script:
-- Compatibility aliases for older Mudlet installs that still call legacy wrapper names.
local function _fc_safe_call(name, ...)
  local fn = _G[name]
  if type(fn) == "function" then
    return fn(...)
  end
  cecho(string.format("<orange>[FantasyCards] Missing function '%s'. Reload the package if this persists.\n", name))
end

function FantasyCards_Alias_Help(matches)
  return _fc_safe_call("Help")
end

function FantasyCards_Alias_Scan(matches)
  return _fc_safe_call("ScanCases")
end
